      console.log('Directional quality:', quality);
    });
  });

  describe('HERRAMIENTA: constellateMemory', () => {
    it('TRANSFORMIS LTM into KG node (sedimentation → node)', async () => {
      const result = await constellateMemory({
        memoryId: 'test-memory-1',
